const Q_COMMERCE_2004=[{"id": "objective>Commerce>2004>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ships that sail across the ocean and operate on scheduled timetables are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ferries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ocean liners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tramp steamers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coastal liners</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean liners Sail through high sea and oceans e.g. Atlantic, Indian and Pacific oceans. It is divided into: Passenger liners and Cargo liners <br/> </div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2004>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Non-insurable risks include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gambling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">damage to property</div>", "<div style=\"font-family:Cambria;font-size:17px;\">death</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marine problems</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gambling is a non-insurable risk in the sense that one of the two parties involved must always suffer a loss which is not good for the insurance business.  </div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2004>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The program that makes up the operating system in a computer is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">microprogram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">system flowchart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">system software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">syntax</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">System software controls a computer's internal functioning, chiefly through an operating system, and also controls such peripherals as monitors, printers, and storage devices.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2004>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an organization studies a market that is underserved by others and creates a product or service for the segment, it is engaged in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market positioning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market orchestration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product differentiation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of studying an underserved market and creating a product or service for that segment is known as market positioning. Market positioning involves identifying a market niche and ensuring that the product or service is attractive to that segment. It's about carving out a spot in the competitive landscape and focusing your company's efforts on it.</div>", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION"}, {"id": "objective>Commerce>2004>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Coverage against unexpected events is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warranty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reinsurance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coverage against unexpected events is called insurance. Insurance is a contract, represented by a policy, in which an individual or entity receives financial protection or reimbursement against losses from an insurance company. The company pools clients' risks to make payments more affordable for the insured.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2004>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An insured risk which occurs accidentally as a result of defects in a ship is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a voyage policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a total loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an emergency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a particular average</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Particular average loss occurs when the cargo or ship suffers partial loss or damage. The loss is accidential.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2004>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Communication enhances business activities by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">facilitating interaction between producers and consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitating interaction among media houses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensuring the movement of goods from the producer to the consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">keeping the goods safe until they are needed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Communication helps to enhance business activities by facilitating interaction between producers and consumers.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES"}, {"id": "objective>Commerce>2004>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In business, the computer is very important especially in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">financial management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educational management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">information management</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Information management helps to keep relevant records to aid in the making of decisions for the progress of business activities. </div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>2004>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the most important use of promotion in marketing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">persuasion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conviction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">information</div>", "<div style=\"font-family:Cambria;font-size:17px;\">education</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important use of promotion in marketing is persuasion. Promotion involves various activities like advertising, sales promotion, public relations, and direct marketing, all aimed at persuading the target audience to buy a product or service. While information and education are also important, the ultimate goal of promotion is to persuade consumers to make a purchase.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2004>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The current highest decision-making body on privatization and commercialization of public enterprises in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Council on Privatization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Investment Promotion Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bureau of Public Enterprises</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The National Council on Privatization (NCP) is the highest decision-making body on privatization and commercialization of public enterprises in Nigeria. The NCP is charged with the overall responsibility of formulating and approving policies on privatization and commercialization. The Securities and Exchange Commission, Nigeria Investment Promotion Commission, and Bureau of Public Enterprises are involved in the process but they do not have the ultimate decision-making power.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2004>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The members of the Niger Basin Commission include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Guinea, Ghana and Niger Republic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Burkina Faso, Guinea and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Gambia, Benin Republic and Chad Republic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria, the Gambia and Cameroon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Members of Niger Basin Commission are: The Republic of Benin,Chad, Cameroun, Guinea, Burkina Faso, Nigeria, Mali, Cote de Ivore and Niger Republic.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2004>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Business environment refers to all elements that are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">outside an organization but relevant to its operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inside an organization but irrelevant to its operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal to an organization and relevant to its operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external to an organization but indirectly related to its operations</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The business environment refers to all elements that are outside an organization but relevant to its operations. These include factors like customers, competitors, suppliers, government, and the economy. While internal factors are also important, the term 'business environment' typically refers to the external factors that can influence a business's success.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>2004>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer rights include the right to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free samples of a product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a share of profits</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consumer has the right to seek redress in a law court when he has been cheated by a seller through the sale of fake or substandard products to him or when unduly charged in form of higher prices.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION"}, {"id": "objective>Commerce>2004>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One important requirement for the membership of the ECOWAS is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">integrity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">landmass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The intended country must have been completely free from its colonial master and must be sovereign in the conduct of its affairs.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2004>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the body that ensures that its members operate according to their professional ethics is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SON</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NPF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MAN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NAFDAC</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the body that ensures that its members operate according to their professional ethics is the Manufacturers Association of Nigeria (MAN). The Standards Organisation of Nigeria (SON) and the National Agency for Food and Drug Administration and Control (NAFDAC) are regulatory bodies that ensure standards are met in their respective sectors, while the Nigeria Police Force (NPF) is a law enforcement agency.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2004>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transporter who had to sell some perishable goods without the prior authority of the owner becomes an agent by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conduct</div>", "<div style=\"font-family:Cambria;font-size:17px;\">necessity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ratification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estoppel</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agency by necessity occurs Where someone who is in the possession of goods of another person does something to the goods in order to protect or save the goods.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2004>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Poor sewage disposal, oil spill and indiscriminate refuse dumping all lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land and water pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air and water pollution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-    Water pollution: Occurs when harmful substances often chemicals or micro organisms contaminate a stream, river, lake, ocean or other body of water and rendering it toxic to humans or the environment. <br/>  <br/> -  Land pollution: Refers to the deterioration of the earth's land surface or it is degradation or destruction of the earth's surface and soil, directly or indirectly as a result of human activities.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : POLLUTION"}, {"id": "objective>Commerce>2004>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the advantages of commercialization is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encourages entrepreneurship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases the salaries of workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motivates government to establish more businesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gives workers on-the-job training</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a bid to ensure maximum profit, commercialization promotes entrepreneurial skills so as to perform effectively and efficiently. </div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2004>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A common element in all contracts is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">offer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceptance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agreement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a contract, both parties involved must agree as to the conditions binding the contract for the success of the contract to be ensured.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>2004>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sources of finance to a business include personal savings, shares, debentures and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loans from IMF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank overdrafts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">central bank loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money from political parties</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Business can source capital from: Personal savings, Loan from friends, Trade credit, Loan and overdraft from banks, Grants/Loans from government.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2004>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Charges for loans paid by commercial banks to the Central Bank of Nigeria are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bank rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank charges</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank rate is the interest rate at which a nation's central bank lends money to domestic banks, often in the form of very short-term loans.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2004>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the primary market, new shares are issued through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">personal selling, publicity and advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a prospectus, an offer for sale and a bill of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising, a prospectus and a bill of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a prospectus, an offer for sale and placing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the primary market, new shares are issued through a prospectus, an offer for sale, and placing. A prospectus is a formal legal document that provides details about an investment offering for sale to the public. An offer for sale is a method of selling shares where a company sells its shares directly to the public. Placing is a method of issuing securities to a small number of selected investors, often institutional.</div>", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS"}, {"id": "objective>Commerce>2004>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instruments of credit include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">billboards and postal stamps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">payment vouchers and statement of account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bills of exchange and promissory notes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bills of exchange and salary vouchers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The instruments of credit include bills of exchange and promissory notes. A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party on demand or at a predetermined date. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2004>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shares of a company listed on the stock exchange for sale are referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">registered shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deferred shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issued shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quoted shares</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quoted shares are shares whose prices are listed on a recognised stock exchange or secondary market. </div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2004>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the role of the capital market in the privatization exercise in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Selling the shares and stocks of the companies to be privatized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encouraging private companies to participate in the exercise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Negotiating with individuals who want to buy public companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Advertising for government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital market has to  be fully alive, one of the objectives of the privatization process is to ensure a more viable capital market within an economy and also the privatization process cannot be carried out successfully without the capital market. The capital market, through the Nigerian stock exchange is saddled with the responsibility of ensuring a successful privatization.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2004>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In international trade, documentary credit is also known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">letters of credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bankers' drafts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">letter of hypothecation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In international trade, documentary credit is also known as 'letters of credit'. A letter of credit is a letter from a bank guaranteeing that a buyer's payment to a seller will be received on time and for the correct amount. In the event that the buyer is unable to make payment on the purchase, the bank will be required to cover the full or remaining amount of the purchase.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2004>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A specialized institution in Nigeria that deals in capital investments in the form of stocks, shares, bonds and debentures is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commodity market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Stock Exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Central Bank of Nigeria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Stock Exchange is a specialized institution in Nigeria that deals in capital investments in the form of stocks, shares, bonds and debentures.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2004>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A group of assets which a business acquires with the intention of reselling them are referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">investment assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intangible assets</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Current assets are a category of assets that a company expects to convert to cash or use up within one year or its operating cycle, whichever is longer. These assets include cash and cash equivalents, marketable securities, accounts receivable, inventory, and prepaid expenses. In this case, the assets that a business acquires with the intention of reselling them are referred to as current assets.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>2004>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Authorized share capital is also known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">called-up share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paid-up share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">registered share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issued share capital</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Authorized share capital, also known as registered share capital, is the maximum amount of share capital that a company is authorized by its constitutional documents to issue (allocate) to shareholders. It is a part of the company's capital structure.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>2004>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An action taken by a company outside its object clause is regarded as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ultra vires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a trespass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uberrima fides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caveat emptor</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ultra vires simply means the principle of law which prescribes that a company cannot act or do anything outside the powers conferred on it by its Memorandum of association.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2004>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The strategy adopted by a firm that ceases to operate at one or more locations because of inactivity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rejuvenation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diversification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The strategy adopted by a firm that ceases to operate at one or more locations because of inactivity is known as consolidation. Consolidation is a business strategy that involves combining multiple business entities or operations into a single, more efficient and competitive entity. It is often used to increase operational efficiency by reducing redundant personnel and processes.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>2004>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A written partnership contract is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a deed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a prospectus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a proposal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A written partnership contract is known as a deed. A deed is a legal document that signifies an agreement or contract between two or more parties. In the context of a partnership, a deed, also known as a partnership deed, outlines the terms and conditions of the partnership.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>2004>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The merger of a textile mill, a cement company and a tannery is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conglomerate merger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal merger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lateral merger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertical merger</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The merger of a textile mill, a cement company and a tannery is referred to as a conglomerate merger. A conglomerate merger is a merger between firms that are involved in totally unrelated business activities. These firms may operate in different industries or different geographical regions. The purpose of a conglomerate merger is often to diversify business operations and investments.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>2004>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> As the branches indicate, IV is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">finance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV represents construction. Occupation is divded into:  <br/>  <br/> - industrial: consist of extraction, manufacturing and construction <br/> - commerce: consist of trade and aids to trade <br/> - service: consist of direct and indirect service</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2004>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What does V represent ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aids to trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industry</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> As the branches indicate, V is represents the aids to trade.  </div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2004>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most importance of computer is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">helping people to improve their profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitating exchanges among individuals and firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assisting trade through banking and insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhancing business relationships</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Computers are used to facilitate exchanges in many ways, including: <br/>  <br/> -    Processing transactions: Computers are used to process transactions such as sales, purchases, and payments. This makes it easier for businesses to track their finances and manage their inventory. <br/> -    Storing data: Computers can store large amounts of data, which can be used to track customer information, product inventory, and financial records. This makes it easier for businesses to make decisions and improve their operations. <br/> -   Communicating: Computers can be used to communicate with customers, suppliers, and other businesses. This can be done through email, online chat, and video conferencing. This makes it easier for businesses to collaborate and build relationships. <br/> -   Providing information: Computers can be used to provide information to customers, employees, and other stakeholders. This can be done through websites, databases, and reports. This makes it easier for businesses to share information and make informed decisions.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : MERITS & DEMERIT"}, {"id": "objective>Commerce>2004>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The acronym PLC is used to identify a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">company limited by shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">private company limited by shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public company limited by shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">company limited by guarantee</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public company limited by shares is the one which raise funds for business through the sales of shares to the members of the public.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2004>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commerce includes all the occupations concerned with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sales</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commerce simply means all the activities involved in the distribution and exchange of goods and services. It is the process of buying, selling and distributing goods and services.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2004>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Factors of production can be described as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">resources required for the provision of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skills involved in deciding and directing the flow of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monetary tools employed by government to ensure stable production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elements involved in the process of formulating policies on production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The factors of production refers to the resources required for the provision of goods and services and they include land, labour, capital and entrepreneur.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2004>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fluctuations in the supply of goods may be eliminated if the distribution system maintains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">modern technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a team of retailers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warehouse services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sufficient middlemen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fluctuations in the supply of goods can be eliminated if the distribution system maintains warehouse services. Warehouses allow for the storage of goods, thereby ensuring that there is a steady supply of goods even when production fluctuates. This is because when production is high, the excess goods can be stored in the warehouse and released when production is low, thereby maintaining a steady supply.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING"}, {"id": "objective>Commerce>2004>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Loan schemes by thrift societies are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mortgage schemes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conventional schemes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutual schemes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unconventional schemes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thrift are savings and loans association; they also refer to credit unions and mutual savings banks that provide a variety of services. Cooperative thrift and credit societies are member-based organisations that help members to address economic problems.  The ultimate goal is to encourage thrift among the members and to meet the credit needs of people who might otherwise be exposed to exploitation.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2004>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An internal demand for goods to be purchased or drawn from stock is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a quotation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a requisition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a tender</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an order</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A stock requisition document requests items stocked in inventory. It is recorded in the system as a pre-encumbrance.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2004>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term 4 net 7 on an invoice means that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4% surcharge will be made unless payment is made within seven days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4% discount will be allowed on the price charged only if the goods are bought within seven days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4% discount will be allowed on the price charged if payment is made after seven days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4% discount will be allowed on the price charge if payment is made within seven days</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term 4 net 7 on an invoice means that 4% discount will be allowed on the price charge if payment is made within seven days.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>2004>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An order sent by an importer to an overseas supplier stating the details of goods required is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">export invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ship's manifest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an indent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of lading</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An indent is a document used in international trade. It is an order to buy goods conveyed by an importer to a potential supplier.  It can be placed with the seller or his agent.  It gives details of the goods required, approximate price, date of delivery etc.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2004>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Organising trade fairs in Nigeria is the responsibility of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Directorate of Employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Ministry of Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trade Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chambers of Commerce</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chamber of commerce promote home and foreign trade, organise trade fairs and exhibitions, collect and disseminate information to members, educate members on government legislation  etc.</div>", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE"}, {"id": "objective>Commerce>2004>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">International trade takes place as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">uniformity in costs of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inequitable distribution of natural resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parity in the level of industrialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">similarities in climatic conditions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reasons for foreign trade are: <br/> - Uneven distribution of natural resources <br/> - Differences in climatic condition <br/> - Differences in technology <br/> - Difference in skills <br/> - Expansion of market for products <br/> - Desire to improve the standard of living  etc.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2004>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of vending machines in retailing is hindered in a developing economy owing to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industrial policy and harmony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low level of education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ineffective communication system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of steady power supply</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vending machine is a retail outlet that automatically dispenses pre-packed items such as drinks stored in it whenever the appropriate value coin is inserted. The disadvantages are: <br/> - No refund of cash balance <br/> - Limited to a range of goods <br/> - It encourages pilfery <br/> - High price of goods <br/> - Low profit <br/> - Reduction in sale</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2004>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigeria contributes to development by advising the government on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industrial policy and harmony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget and budgetary control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget and industrial policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental protection policy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigeria contributes to development by advising the government on industrial policy and harmony.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2004>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Discounts offered by firms to middlemen for bulk purchases are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trade discounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales bonanza</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash discounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonal discounts</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trade discounts is opposed to cash discount as trade discount is a discount on the retail price of something allowed or agreed between traders or to a retailer by a wholesaler.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2004>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Goods are of merchantable quality if they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conform to description</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are of equal weight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">care of the same quality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conform to buyers purpose</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Goods are of merchantable quality when they are of use for the purpose for which the goods are ordinarily used.</div>", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS"}];
